from __future__ import annotations
from typing import Any


def build_answers(ctx: dict[str, Any]) -> dict[str, str]:
    return {'reminder_effect': 'The current project does not claim reminders work. It provides predictive targeting and an experiment design; effectiveness requires randomised or otherwise defensible causal evaluation.', 'pilot_size': f"At baseline DNA {ctx['_pct'](ctx['pilot']['baseline_dna_rate'])} and assumed {ctx['default_effect']:.0%} relative reduction, the approximation requires {int(ctx['pilot']['total_sample_size']):,} appointments, about {int(ctx['pilot']['weeks_at_recruitment_capacity'])} weeks at configured recruitment capacity.", 'pilot_guardrails': f"The pilot specifies {len(ctx['experiment_guardrails'])} guardrails, including {', '.join(ctx['experiment_guardrails']['metric'].head(3))}. These should have thresholds and stopping rules before rollout.", 'causal_design': 'Randomisation is preferred for a low-risk additional reminder workflow. If infeasible, define the target trial, treatment timing, confounders and estimand before using weighting, matching or outcome regression, and report sensitivity to unmeasured confounding.', 'phased_rollout': 'For phased rollout, record unit and start date before launch, check pre-trends, model concurrent changes and use stepped-wedge, difference-in-differences or interrupted time series according to the assignment mechanism.'}
